func  (this *ToobitCore) ParseTrade(trade any, optionalArgs ...any) any  {
    //
    // fetchTrades
    //
    //        {
    //            "t": "1755594277287",
    //            "p": "115276.99",
    //            "q": "0.001508",
    //            "ibm": true
    //        },
    //        // watchTrades have also an additional fields:
    //             "v": "4864732022868004630",   // trade id
    //             "m": true,                    // is the buyer taker
    //
    // fetchMyTrades
    //
    //        {
    //            "id": "2024934575206059008",
    //            "symbol": "ETHUSDT",
    //            "orderId": "2024934575097029888",
    //            "ticketId": "4864450547563401875",
    //            "price": "4641.21",
    //            "qty": "0.001",
    //            "time": "1756127012094",
    //            "isMaker": false,
    //            "commission": "0.00464121",
    //            "commissionAsset": "USDT",
    //            "makerRebate": "0",
    //            "symbolName": "ETHUSDT",                 // only in SPOT
    //            "isBuyer": false,                        // only in SPOT
    //            "feeAmount": "0.00464121",               // only in SPOT
    //            "feeCoinId": "USDT",                     // only in SPOT
    //            "fee": {                                 // only in SPOT
    //                "feeCoinId": "USDT",
    //                "feeCoinName": "USDT",
    //                "fee": "0.00464121"
    //            },
    //            "type": "LIMIT",                         // only in CONTRACT
    //            "side": "BUY_OPEN",                      // only in CONTRACT
    //            "realizedPnl": "0",                      // only in CONTRACT
    //        },
    //
    market := GetArg(optionalArgs, 0, nil)
    _ = market
    var timestamp any = this.SafeInteger2(trade, "t", "time")
    var priceString any = this.SafeString2(trade, "p", "price")
    var amountString any = this.SafeString2(trade, "q", "qty")
    var isBuyer any = this.SafeBool(trade, "isBuyer")
    var side any = nil
    var isBuyerMaker any = this.SafeBool(trade, "ibm")
    if IsTrue(IsEqual(isBuyerMaker, nil)) {
        var isBuyerTaker any = this.SafeBool(trade, "m")
        if IsTrue(!IsEqual(isBuyerTaker, nil)) {
            isBuyerMaker = !IsTrue(isBuyerTaker)
        }
    }
    if IsTrue(!IsEqual(isBuyerMaker, nil)) {
        if IsTrue(isBuyerMaker) {
            side = "sell"
        } else {
            side = "buy"
        }
    } else {
        if IsTrue(isBuyer) {
            side = "buy"
        } else {
            side = "sell"
        }
    }
    var feeCurrencyId any = this.SafeString(trade, "feeCoinId")
    var feeAmount any = this.SafeString(trade, "feeAmount")
    var fee any = nil
    if IsTrue(!IsEqual(feeAmount, nil)) {
        fee = map[string]any {
            "currency": this.SafeCurrencyCode(feeCurrencyId),
            "cost": feeAmount,
        }
    }
    var isMaker any = this.SafeBool(trade, "isMaker")
    var takerOrMaker any = nil
    if IsTrue(!IsEqual(isMaker, nil)) {
        takerOrMaker = Ternary(IsTrue(isMaker), "maker", "taker")
    }
    market = this.SafeMarket(nil, market)
    var symbol any = GetValue(market, "symbol")
    return this.SafeTrade(map[string]any {
        "info": trade,
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "symbol": symbol,
        "id": this.SafeString2(trade, "id", "v"),
        "order": this.SafeString(trade, "orderId"),
        "type": nil,
        "side": side,
        "amount": amountString,
        "price": priceString,
        "cost": nil,
        "takerOrMaker": takerOrMaker,
        "fee": fee,
    }, market)
}
