func  (this *ToobitCore) ParseTransaction(transaction any, optionalArgs ...any) any  {
    //
    // fetchDeposits & fetchWithdrawals
    //
    //     {
    //         "time": 1499865549590,
    //         "id": 100234,
    //         "coinName": "EOS",
    //         "statusCode": "DEPOSIT_CAN_WITHDRAW",
    //         "status": "2", // 2=SUCCESS, 11=REJECT, 12=AUDIT
    //         "address": "deposit2bb",
    //         "txId": "98A3EA560C6B3336D348B6C83F0F95ECE4F1F5919E94BD006E5BF3BF264FACFC",
    //         "txIdUrl": "",
    //         "requiredConfirmTimes": "5",
    //         "confirmTimes": "5",
    //         "quantity": "1.01",
    //         "coin": "EOS",                     // present in "fetchDeposits"
    //         "coinId ":"BHC",                   // present in "fetchWithdrawals"
    //         "addressTag": "19012584",          // present in "fetchDeposits"
    //         "addressExt":"address tag",        // present in "fetchWithdrawals"
    //         "fromAddress": "clarkkent",        // present in "fetchDeposits"
    //         "fromAddressTag": "19029901"       // present in "fetchDeposits"
    //         "arriveQuantity":"14",             // present in "fetchWithdrawals"
    //         "walletHandleTime":"1536232111669",// present in "fetchWithdrawals"
    //         "feeCoinId ":"BHC",                // present in "fetchWithdrawals"
    //         "feeCoinName ":"BHC",              // present in "fetchWithdrawals"
    //         "fee":"0.1",                       // present in "fetchWithdrawals"
    //         "kernelId":"",                     // present in "fetchWithdrawals"
    //         "isInternalTransfer": false        // present in "fetchWithdrawals"
    //     }
    //
    // withdraw
    //
    //     {
    //         "status": 0,
    //         "success": true,
    //         "needBrokerAudit": false, // Do you need a brokerage review?
    //         "id": "423885103582776064",
    //         "refuseReason":"" // failure rejection reason
    //     }
    //
    currency := GetArg(optionalArgs, 0, nil)
    _ = currency
    var timestamp any = this.SafeInteger(transaction, "time")
    var currencyId any = this.SafeString2(transaction, "coin", "coinId")
    var code any = this.SafeCurrencyCode(currencyId, currency)
    var feeString any = this.SafeString(transaction, "fee")
    var feeCoin any = this.SafeString(transaction, "feeCoinName")
    var fee any = nil
    if IsTrue(!IsEqual(feeString, nil)) {
        fee = map[string]any {
            "cost": this.ParseNumber(feeString),
            "currency": this.SafeCurrencyCode(feeCoin),
        }
    }
    var tagTo any = this.SafeString2(transaction, "addressTag", "addressExt")
    var tagFrom any = this.SafeString(transaction, "fromAddressTag")
    var addressTo any = this.SafeString(transaction, "address")
    var addressFrom any = this.SafeString(transaction, "fromAddress")
    var isWithdraw any =     (InOp(transaction, "arriveQuantity"))
    var typeVar any = Ternary(IsTrue(isWithdraw), "withdrawal", "deposit")
    return map[string]any {
        "info": transaction,
        "id": this.SafeString(transaction, "id"),
        "txid": this.SafeString(transaction, "txId"),
        "timestamp": timestamp,
        "datetime": this.Iso8601(timestamp),
        "network": nil,
        "address": nil,
        "addressTo": addressTo,
        "addressFrom": addressFrom,
        "tag": nil,
        "tagTo": tagTo,
        "tagFrom": tagFrom,
        "type": typeVar,
        "amount": this.SafeNumber(transaction, "quantity"),
        "currency": code,
        "status": this.ParseTransactionStatus(this.SafeString(transaction, "status")),
        "updated": nil,
        "fee": fee,
        "comment": nil,
        "internal": nil,
    }
}
func  (this *ToobitCore) ParseTransactionStatus(status any) any  {
    var statuses any = map[string]any {
        "2": "pending",
        "12": "pending",
        "11": "failed",
        "3": "ok",
    }
    return this.SafeString(statuses, status, status)
}
